import Foundation

let questions2: [QuizQuestion] = [
    // SALMOS E PROVÉRBIOS (121-280)
    QuizQuestion(id:121, question:"Com qual figura o Salmo 23 compara o Senhor?", options:["Leão","Pastor","Águia","Rocha"], correctIndex:1, explanation:"'O Senhor é o meu pastor; nada me faltará.' Davi usou a imagem do pastor para descrever o cuidado amoroso de Deus.", reference:"Salmos 23:1", category:.salmos, propheticMeaning:"Jesus declarou ser o Bom Pastor (Jo 10:11), cumprindo o Salmo 23. O pastor que guia, alimenta, restaura e protege é Jesus — e 'morarei na casa do Senhor para sempre' é a promessa da vida eterna com ele."),
    QuizQuestion(id:122, question:"Quem escreveu a maioria dos Salmos?", options:["Moisés","Salomão","Davi","Asafe"], correctIndex:2, explanation:"Davi escreveu mais da metade dos 150 Salmos, sendo chamado 'o músico suave de Israel'.", reference:"2 Samuel 23:1", category:.salmos, propheticMeaning:"Davi, o pastor que virou rei, é tipo de Cristo. Muitos salmos de Davi são profecias messiânicas — especialmente Salmos 22 (crucificação) e 110 (sacerdócio eterno de Cristo), citados no NT como cumpridos em Jesus."),
    QuizQuestion(id:123, question:"Qual é o versículo inicial do Salmo 23?", options:["'Bendize, ó minha alma, ao Senhor'","'O Senhor é a minha luz e a minha","'Como é amável a tua morada'","'O Senhor é o meu pastor"], correctIndex:3, explanation:"O Salmo 23 começa com a famosa declaração de confiança: 'O Senhor é o meu pastor; nada me faltará.'", reference:"Salmos 23:1", category:.salmos, propheticMeaning:"A afirmação 'nada me faltará' é a consequência lógica de ter o Senhor como pastor. Cristo provê tudo — vida, paz, restauração, proteção, justiça e habitação eterna."),
    QuizQuestion(id:124, question:"Segundo o Salmo 1, o homem bem-aventurado é aquele que:", options:["Não anda no conselho dos","Tem muitas riquezas","Ora três vezes ao dia","Jejua regularmente"], correctIndex:0, explanation:"O Salmo 1 descreve o homem bem-aventurado como aquele que rejeita o conselho dos ímpios e medita na lei do Senhor de dia e de noite, sendo como árvore plantada junto a ribeiros de águas.", reference:"Salmos 1:1-3", category:.salmos, propheticMeaning:"O homem do Salmo 1 é o ideal messiânico cumprido perfeitamente em Cristo — o único que nunca andou no conselho dos ímpios e cujo deleite era sempre fazer a vontade do Pai (Jo 4:34)."),
    QuizQuestion(id:125, question:"O Salmo 22 começa com quais palavras que Jesus citou na cruz?", options:["'Bom é louvar ao Senhor'","'Deus meu, Deus meu","'O Senhor é a minha força'","'Cantai ao Senhor um cântico novo'"], correctIndex:1, explanation:"O Salmo 22 começa com 'Deus meu, Deus meu, por que me abandonaste?', clamor que Jesus expressou na cruz conforme registrado em Mateus 27:46.", reference:"Salmos 22:1; Mateus 27:46", category:.salmos, propheticMeaning:"O Salmo 22 foi escrito 1000 anos antes de Cristo e descreve a crucificação com detalhes impossíveis para Davi (mãos e pés traspassados, roupas divididas por sorteio) — confirma a autoria divina e a identidade messiânica de Jesus."),
    QuizQuestion(id:126, question:"Qual salmo diz 'Criou em mim, ó Deus, um coração puro'?", options:["Salmo 1","Salmo 23","Salmo 51","Salmo 91"], correctIndex:2, explanation:"O Salmo 51 foi escrito por Davi após seu pecado com Bate-Seba. Nele ele clama: 'Cria em mim, ó Deus, um coração puro e renova em mim um espírito reto'.", reference:"Salmos 51:10", category:.salmos, propheticMeaning:"O Salmo 51 é o modelo do arrependimento genuíno. Davi reconhece que só Deus pode criar um coração novo — o que no NT é chamado de novo nascimento e regeneração pelo Espírito Santo."),
    QuizQuestion(id:127, question:"O que diz o Salmo 91:11 sobre os anjos?", options:["Que os anjos cantam ao Senhor","Que os anjos habitam no céu","Que os anjos revelam segredos divinos","Que Deus dará ordens aos seus anjos para..."], correctIndex:3, explanation:"'Porque dará ordens aos seus anjos a teu respeito, para te guardarem em todos os teus caminhos.' O diabo até citou este versículo tentando Jesus.", reference:"Salmos 91:11; Mateus 4:6", category:.salmos, propheticMeaning:"O Salmo 91 é chamado de 'o salmo da proteção divina'. Os anjos ministradores (Hb 1:14) cumprem esse versículo diariamente na vida dos crentes. Jesus — habitando 'no esconderijo do Altíssimo' — é o cumprimento perfeito deste salmo."),
    QuizQuestion(id:128, question:"Qual é o salmo mais longo da Bíblia?", options:["Salmo 119","Salmo 23","Salmo 91","Salmo 150"], correctIndex:0, explanation:"O Salmo 119 é o mais longo da Bíblia, com 176 versículos, e é um poema acróstico hebraico celebrando a Palavra de Deus.", reference:"Salmos 119", category:.salmos, propheticMeaning:"O Salmo 119 glorifica a Palavra de Deus em todas as suas formas: lei, testemunhos, mandamentos, julgamentos, estatutos. Cristo é a Palavra encarnada (Jo 1:14) — o cumprimento pessoal de tudo o que o Salmo 119 celebra."),
    QuizQuestion(id:129, question:"O que diz o Salmo 119:105?", options:["'O Senhor é minha rocha'","'Lâmpada para os meus pés é a tua","'Cantarei ao Senhor enquanto viver'","'Deus é nosso refúgio e fortaleza'"], correctIndex:1, explanation:"'Lâmpada para os meus pés é a tua palavra e luz para o meu caminho.' A Palavra de Deus ilumina cada passo do crente na escuridão deste mundo.", reference:"Salmos 119:105", category:.salmos, propheticMeaning:"A Palavra que ilumina o caminho aponta para Cristo, a Palavra encarnada (Jo 1:1) e a Luz do mundo (Jo 8:12). A Bíblia e Cristo são inseparáveis: conhecer as Escrituras é conhecer a ele."),
    QuizQuestion(id:130, question:"Qual salmo começa com 'Deus é o nosso refúgio e fortaleza, socorro bem presente nas tribulações'?", options:["Salmo 23","Salmo 91","Salmo 46","Salmo 121"], correctIndex:2, explanation:"O Salmo 46:1 declara: 'Deus é o nosso refúgio e fortaleza, socorro bem presente nas tribulações.' Este salmo inspirou Martinho Lutero a escrever 'Castelo Forte é nosso Deus'.", reference:"Salmos 46:1", category:.salmos, propheticMeaning:"O Deus que é refúgio e fortaleza se revelou em Cristo — Emanuel, Deus conosco nas tribulações. No Salmo 46, 'um rio' representa a presença de Deus (cf. Jo 7:38 — rios de água viva fluindo do crente)."),
    QuizQuestion(id:131, question:"Qual salmo diz 'Ergo os meus olhos para os montes. De onde me virá o socorro?'?", options:["Salmo 23","Salmo 91","Salmo 150","Salmo 121"], correctIndex:3, explanation:"O Salmo 121 começa com 'Ergo os meus olhos para os montes; de onde me virá o socorro? O meu socorro vem do Senhor, que fez os céus e a terra.'", reference:"Salmos 121:1-2", category:.salmos, propheticMeaning:"O socorro que vem do Senhor é Cristo — 'o guardador de Israel não dormitará nem dormirá' (v.4). Na vida do crente, Jesus é o guardador fiel que nos preserva na saída e na entrada, agora e para sempre."),
    QuizQuestion(id:132, question:"O Salmo 110 começa com quais palavras proféticas sobre o Messias?", options:["'O Senhor disse ao meu Senhor:","'O Senhor é o meu pastor'","'Louvai o Senhor, todas as nações'","'Cantai ao Senhor um cântico novo'"], correctIndex:0, explanation:"'Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos por escabelo dos teus pés.' Jesus citou este salmo para provar sua divindade.", reference:"Salmos 110:1; Mateus 22:44", category:.salmos, propheticMeaning:"O Salmo 110 é o mais citado no NT. Mostra o Messias reinando à direita de Deus e sendo Sacerdote para sempre segundo a ordem de Melquisedeque (Hb 7:17). Cristo ressurreto cumpre literalmente: está sentado à direita do Pai."),
    QuizQuestion(id:133, question:"Quantos Salmos existem na Bíblia?", options:["100","150","120","180"], correctIndex:1, explanation:"O livro dos Salmos tem 150 poemas e cânticos de louvor, lamento, gratidão e adoração, divididos em 5 livros.", reference:"Livro dos Salmos", category:.salmos, propheticMeaning:"Os 5 livros dos Salmos correspondem aos 5 livros de Moisés. Os Salmos são a resposta do povo de Deus à sua lei e suas obras — louvor à revelação divina que culmina em Cristo, a Palavra viva."),
    QuizQuestion(id:134, question:"Segundo Provérbios, qual é o princípio da sabedoria?", options:["O amor ao próximo","A busca do conhecimento","O temor do Senhor","A humildade"], correctIndex:2, explanation:"'O temor do Senhor é o princípio da sabedoria, e o conhecimento do Santo é a inteligência.' Temer a Deus significa respeitá-lo profundamente.", reference:"Provérbios 9:10", category:.salmos, propheticMeaning:"Cristo se tornou para nós sabedoria de Deus (1 Co 1:30). Toda a sabedoria dos Provérbios culmina nele — o Filho de Deus que personificou o temor ao Pai e é o repositório de todos os tesouros da sabedoria (Cl 2:3)."),
    QuizQuestion(id:135, question:"O que diz Provérbios 3:5-6?", options:["'O temor do Senhor é o princípio da","'O filho sábio alegra ao pai'","'Como o ferro afia o ferro","'Confia no Senhor de todo o teu coração"], correctIndex:3, explanation:"'Confia no Senhor de todo o teu coração e não te estribes no teu próprio entendimento. Reconhece-o em todos os teus caminhos, e ele endireitará as tuas veredas.'", reference:"Provérbios 3:5-6", category:.salmos, propheticMeaning:"Confiar em Deus em vez do raciocínio humano é o fundamento da fé. Jesus demonstrou isso perfeitamente ao confiar no Pai mesmo diante da morte. O cristão que 'reconhece a Deus em todos os caminhos' vive a vida de Cristo."),
    QuizQuestion(id:136, question:"Qual é a personagem feminina de Provérbios 31?", options:["A mulher virtuosa","A mulher sedutora","A mulher sábia","A mulher fiel"], correctIndex:0, explanation:"Provérbios 31 descreve a mulher virtuosa, cujo valor ultrapassa o de rubis. Ela é trabalhadora, cuidadosa com a família e teme a Deus.", reference:"Provérbios 31:10-31", category:.salmos, propheticMeaning:"A mulher virtuosa de Pv 31 é tipo da Igreja fiel — esposa de Cristo que é diligente, produtiva e cujo coração está voltado para o Senhor. Suas obras a louvam nas portas como os servos de Deus são reconhecidos no dia do Senhor."),
    QuizQuestion(id:137, question:"O que diz Eclesiastes sobre a vaidade das coisas?", options:["'Tudo tem seu tempo debaixo do sol'","'Vaidade das vaidades, diz o pregador","'O temor de Deus é o dever de todo homem'","'Há tempo para nascer e tempo para morrer'"], correctIndex:1, explanation:"Eclesiastes abre com 'Vaidade das vaidades, diz o pregador; vaidade das vaidades! Tudo é vaidade.' Salomão reflete sobre a futilidade da vida sem Deus.", reference:"Eclesiastes 1:2", category:.salmos, propheticMeaning:"A 'vaidade' (hebel, sopro, vapor) de Eclesiastes descreve a impermanência de tudo sem Deus. Cristo dá sentido eterno à existência humana — 'em Cristo' nada é em vão (1 Co 15:58), ao contrário de tudo 'debaixo do sol'."),
    QuizQuestion(id:138, question:"O que Eclesiastes diz sobre a conclusão de todo o ensinamento?", options:["'Busca a riqueza acima de tudo'","'A sabedoria é a maior riqueza'","'Teme a Deus e guarda os seus","'Aproveita a juventude ao máximo'"], correctIndex:2, explanation:"Após explorar todas as áreas da vida, Salomão conclui: 'Teme a Deus e guarda os seus mandamentos, porque isto é o dever de todo homem', pois Deus julgará todas as obras.", reference:"Eclesiastes 12:13-14", category:.salmos, propheticMeaning:"A conclusão de Eclesiastes aponta para o julgamento de Deus — que Jesus tornará realidade. O 'dever de todo homem' é crer em Cristo (Jo 6:29), o cumprimento de toda a lei e sabedoria de Deus."),
    QuizQuestion(id:139, question:"O que diz Provérbios 22:6 sobre a criação dos filhos?", options:["'Corrija seu filho e ele será sábio'","'O filho sábio alegra ao pai'","'Castiga seu filho e haverá esperança'","'Instrui a criança no caminho em que deve"], correctIndex:3, explanation:"'Instrui a criança no caminho em que deve andar; e até quando envelhecer não se desviará dele.' É uma promessa sobre o impacto duradouro da educação bíblica.", reference:"Provérbios 22:6", category:.salmos, propheticMeaning:"O 'caminho em que deve andar' é Cristo (Jo 14:6). Introduzir crianças a Jesus desde cedo planteia sementes que o Espírito Santo rega ao longo de toda a vida. A educação bíblica é investimento eterno."),
    QuizQuestion(id:140, question:"O que diz Provérbios sobre a língua?", options:["'A morte e a vida estão no poder da","'A língua sábia cura'","'O homem sábio controla sua língua'","Todas as anteriores estão em Provérbios"], correctIndex:0, explanation:"'A morte e a vida estão no poder da língua, e aquele que a ama comerá do seu fruto' (Pv 18:21). As palavras têm poder de edificar ou destruir.", reference:"Provérbios 18:21", category:.salmos, propheticMeaning:"O poder das palavras em Provérbios ecoa a criação por meio da Palavra (Gn 1) e culmina em Cristo, a Palavra viva. Tiago 3 usa a mesma metáfora ensinando que a língua controlada pelo Espírito edifica; a não controlada destrói."),
    QuizQuestion(id:141, question:"Qual salmo fala de Deus como luz e salvação?", options:["Salmo 22","Salmo 27","Salmo 23","Salmo 46"], correctIndex:1, explanation:"O Salmo 27 começa: 'O Senhor é a minha luz e a minha salvação; a quem temerei? O Senhor é a força da minha vida; a quem me recearei?'", reference:"Salmos 27:1", category:.salmos, propheticMeaning:"Jesus é a Luz do mundo (Jo 8:12) e a salvação de Deus (seu nome 'Yeshua' significa 'Deus salva'). Davi cantou sobre quem viria séculos depois — o Messias que é simultaneamente luz, salvação e fortaleza."),
    QuizQuestion(id:142, question:"O que o Salmo 139 diz sobre o conhecimento de Deus?", options:["Que Deus sabe tudo apenas sobre os reis","Que Deus observa apenas as nações","Que Deus nos conhece intimamente","Que o conhecimento de Deus é um mistério"], correctIndex:2, explanation:"O Salmo 139 exalta a onisciência de Deus: ele conhece cada movimento, pensamento e palavra antes de ser pronunciada. Não há lugar onde fugir de sua presença.", reference:"Salmos 139:1-4", category:.salmos, propheticMeaning:"O Deus onisciente de Salmos 139 se revelou em Cristo — que conhecia os pensamentos dos homens (Mc 2:8), sabia o que havia no coração de cada pessoa (Jo 2:25) e nos conhece pelo nome (Jo 10:3)."),
    QuizQuestion(id:143, question:"Qual salmo foi cantado durante a última ceia, conforme a tradição judaica?", options:["Salmos 22-23","Salmos 120-134","Salmos 146-150","Salmos 113-118"], correctIndex:3, explanation:"A tradição judaica da Páscoa inclui cantar o Hallel (Salmos 113-118). Mateus 26:30 diz que depois da ceia 'cantaram um hino e saíram para o Monte das Oliveiras'.", reference:"Mateus 26:30; Salmos 113-118", category:.salmos, propheticMeaning:"Jesus cantou o Hallel antes de ir para Getsêmani e à cruz. O Salmo 118:22 ('A pedra que os construtores rejeitaram...') estava entre eles — Jesus cantou sua própria profecia antes de cumpri-la horas depois."),
    QuizQuestion(id:144, question:"O que diz Provérbios 4:23?", options:["'Sobre tudo o que se deve guardar","'Antes da queda vem o orgulho'","'Como o ferro afia o ferro","'O orgulho precede a destruição'"], correctIndex:0, explanation:"'Sobre tudo o que se deve guardar, guarda o teu coração, porque dele procedem as fontes da vida.' O coração é o centro moral e espiritual do ser humano.", reference:"Provérbios 4:23", category:.salmos, propheticMeaning:"Guardar o coração é o foco da vida espiritual. Cristo ensinou que do coração procedem as ações (Mt 15:19). A solução não é autocontrole, mas o novo coração prometido em Ezequiel 36:26, dado pelo Espírito Santo."),
    QuizQuestion(id:145, question:"O que diz o Salmo 37:4?", options:["'Confie em Deus e ele te dará saúde'","'Deleita-te no Senhor","'Busca ao Senhor e serás salvo'","'O Senhor guarda o caminho dos justos'"], correctIndex:1, explanation:"'Deleita-te no Senhor, e ele te concederá o que deseja o teu coração.' Quando nosso maior deleite é Deus, nossos desejos se alinham com os dele.", reference:"Salmos 37:4", category:.salmos, propheticMeaning:"O deleite em Deus é o coração da adoração. Quando Cristo é nossa satisfação suprema, nossos desejos são purificados. Agostinho disse: 'Nosso coração é inquieto até repousar em Ti, Senhor' — o Salmo 37:4 em forma de oração."),
    QuizQuestion(id:146, question:"Quem escreveu o livro de Provérbios principalmente?", options:["Davi","Asafe","Salomão","Moisés"], correctIndex:2, explanation:"Salomão é o principal autor de Provérbios. Deus lhe concedeu sabedoria excepcional, e ele expressou essa sabedoria em mais de 3.000 provérbios.", reference:"Provérbios 1:1; 1 Reis 4:32", category:.salmos, propheticMeaning:"Salomão, o mais sábio dos reis, é tipo de Cristo, 'em quem estão escondidos todos os tesouros da sabedoria e do conhecimento' (Cl 2:3). A sabedoria de Salomão foi sombra; a sabedoria de Cristo é a realidade."),
    QuizQuestion(id:147, question:"O que diz Provérbios 16:18?", options:["'Melhor é o pobre que anda em sua...","'A bondade e a fidelidade não te","'O coração do homem planeja o seu caminho'","'O orgulho precede a destruição"], correctIndex:3, explanation:"'O orgulho precede a destruição, e o espírito altivo precede a queda.' A soberba é o pecado original de Satanás e a raiz de toda queda.", reference:"Provérbios 16:18", category:.salmos, propheticMeaning:"O orgulho que destrói contrasta com a humildade de Cristo — 'humilhou-se a si mesmo, tornando-se obediente até à morte' (Fp 2:8). O caminho do orgulho leva à queda; o caminho da humildade, à exaltação por Deus."),
    QuizQuestion(id:148, question:"Qual salmo expressa arrependimento profundo de Davi após o pecado com Bate-Seba?", options:["Salmo 51","Salmo 23","Salmo 32","Salmo 71"], correctIndex:0, explanation:"O Salmo 51 é o salmo penitencial por excelência, escrito após Natã confrontar Davi sobre seu pecado com Bate-Seba e a morte de Urias.", reference:"Salmos 51; 2 Samuel 12", category:.salmos, propheticMeaning:"O Salmo 51 revela que o verdadeiro arrependimento reconhece o pecado como contra Deus (v.4), pede purificação pelo sangue (v.7 — 'purifica-me com hissopo'), e clama por um coração novo (v.10) — tudo cumprido em Cristo."),
    QuizQuestion(id:149, question:"O que diz Provérbios 18:10?", options:["'A língua tem poder de vida e morte'","'O nome do Senhor é uma torre forte'","'Quem achar esposa, acha o bem'","'O coração do homem pode fazer planos'"], correctIndex:1, explanation:"'O nome do Senhor é uma torre forte; o justo corre para ela e fica protegido.' O nome de Deus representa seu caráter e poder, e é refúgio para quem confia nele.", reference:"Provérbios 18:10", category:.salmos, propheticMeaning:"Correr ao nome do Senhor é correr a Cristo — 'não há em nenhum outro salvação, pois, debaixo do céu, não há nenhum outro nome... pelo qual devamos ser salvos' (At 4:12). Jesus é a torre forte onde os crentes encontram segurança eterna."),
    QuizQuestion(id:150, question:"Qual salmo faz referência ao Messias como 'Sacerdote para sempre segundo a ordem de Melquisedeque'?", options:["Salmo 2","Salmo 22","Salmo 110","Salmo 118"], correctIndex:2, explanation:"O Salmo 110:4 declara: 'Tu és sacerdote para sempre, segundo a ordem de Melquisedeque', profecia cumprida em Jesus como nosso Sumo Sacerdote eterno.", reference:"Salmos 110:4; Hebreus 7:17", category:.salmos, propheticMeaning:"Melquisedeque — rei de Salém e sacerdote do Deus Altíssimo sem genealogia registrada — é tipo de Cristo, cujo sacerdócio eterno não se baseia em linhagem humana mas em poder de vida indissolúvel (Hb 7:16)."),
    QuizQuestion(id:151, question:"O que diz o Salmo 2 sobre o Messias?", options:["Que ele será um pastor","Que ele suportará sofrimento","Que ele construirá o templo","Que Deus o estabeleceu como Rei"], correctIndex:3, explanation:"O Salmo 2 apresenta Deus dizendo ao Messias: 'Tu és meu Filho; eu hoje te gerei', estabelecendo-o como Rei em Sião sobre as nações.", reference:"Salmos 2:7-8", category:.salmos, propheticMeaning:"O Salmo 2 é citado no batismo de Jesus (Mt 3:17), na transfiguração (Mt 17:5), na ressurreição (At 13:33) e em Apocalipse 2:27. O Rei ungido em Sião é Jesus, que regerá as nações com vara de ferro na consumação."),
    QuizQuestion(id:152, question:"Qual versículo de Provérbios fala sobre dar e receber?", options:["'Há quem dê livremente e fique mais rico","'Dar é mais abençoado do que receber'","'O avarento se apressa para ficar rico'","'A generosidade traz honra'"], correctIndex:0, explanation:"Provérbios 11:24: 'Há quem dê livremente e fique mais rico; e quem poupe mais do que o devido, mas fique mais pobre.' A generosidade é princípio do Reino.", reference:"Provérbios 11:24", category:.salmos, propheticMeaning:"O paradoxo da generosidade em Provérbios ecoa o evangelho: quem perder a vida a achará (Mt 16:25). Cristo, sendo rico, se fez pobre para que por sua pobreza fôssemos enriquecidos (2 Co 8:9) — a máxima expressão desse princípio."),
    QuizQuestion(id:153, question:"O que diz o Salmo 34:8?", options:["'Clamei ao Senhor e ele me respondeu'","'Provai e vede que o Senhor é bom'","'O anjo do Senhor acampa ao redor dos que...","'Abençoarei o Senhor em todo o tempo'"], correctIndex:1, explanation:"'Provai e vede que o Senhor é bom; bem-aventurado o homem que nele confia.' É um convite à experiência pessoal com Deus.", reference:"Salmos 34:8", category:.salmos, propheticMeaning:"'Provai e vede' é linguagem de experiência, não apenas teologia. Pedro cita este versículo referindo-se a Cristo (1 Pe 2:3): o 'Senhor bom' é Jesus — provar de sua graça transforma a vida para sempre."),
    QuizQuestion(id:154, question:"O que faz o Salmo 150, o último dos Salmos?", options:["Lamenta os pecados de Israel","Profetiza sobre a vinda do Messias","Convoca toda criação a louvar ao Senhor","Pede proteção para o rei"], correctIndex:2, explanation:"O Salmo 150 é o grande hallelujah final: convoca a louvar a Deus no santuário, no firmamento, com instrumentos e dança, terminando com 'Tudo que tem fôlego louve ao Senhor'.", reference:"Salmos 150", category:.salmos, propheticMeaning:"'Tudo que tem fôlego louve ao Senhor' aponta para a adoração universal que toda criação oferecerá a Cristo na consumação: 'Todo joelho se dobrará e toda língua confessará que Jesus Cristo é Senhor' (Fp 2:10-11)."),
    QuizQuestion(id:155, question:"O que Salomão pediu a Deus quando foi coroado rei?", options:["Riqueza e honra","Uma longa vida","Vitória sobre os inimigos","Sabedoria para governar seu"], correctIndex:3, explanation:"Deus se manifestou a Salomão em sonho e disse que pedisse o que quisesse. Salomão pediu sabedoria para governar o povo, o que agradou a Deus que lhe deu sabedoria e também riqueza e honra.", reference:"1 Reis 3:9-13", category:.salmos, propheticMeaning:"Salomão pedindo sabedoria em vez de riqueza é modelo de valores do Reino. Cristo, 'em quem estão todos os tesouros da sabedoria' (Cl 2:3), é a resposta definitiva ao clamor por sabedoria — ele próprio é a Sabedoria de Deus (1 Co 1:24)."),
    QuizQuestion(id:156, question:"O que diz Provérbios 13:20 sobre as companhias?", options:["'Quem anda com sábios se tornará sábio'","'Quem anda com loucos sofrerá dano'","'As más companhias corrompem os bons","'Escolhe teus amigos com cuidado'"], correctIndex:0, explanation:"'Quem anda com sábios ficará sábio, mas o companheiro dos loucos será destruído.' As companhias moldam o caráter.", reference:"Provérbios 13:20", category:.salmos, propheticMeaning:"O princípio da influência mútua culmina em Cristo: 'maus hábitos corrompem bons costumes' (1 Co 15:33), mas andar com Jesus — ouvindo sua voz e seguindo seus passos — nos transforma à sua imagem (2 Co 3:18)."),
    QuizQuestion(id:157, question:"Qual salmo fala de rios de Babilônia onde os israelitas choraram?", options:["Salmo 46","Salmo 137","Salmo 126","Salmo 147"], correctIndex:1, explanation:"O Salmo 137:1 diz: 'À beira dos rios da Babilônia nos assentamos e choramos, quando nos lembramos de Sião.' Foi escrito durante o cativeiro babilônico.", reference:"Salmos 137:1", category:.salmos, propheticMeaning:"O exílio na Babilônia é imagem do estado do pecador distante de Deus — longe de Sião, chorando junto a rios estrangeiros. Cristo veio libertar os cativos (Is 61:1) e nos restaurar à presença do Pai, o verdadeiro Sião."),
    QuizQuestion(id:158, question:"O que diz o Salmo 46:10?", options:["'O Senhor está comigo, não temerei'","'Deus é nosso refúgio e fortaleza'","'Aquietai-vos e sabei que eu sou Deus'","'Cantai ao Senhor um cântico novo'"], correctIndex:2, explanation:"'Aquietai-vos e sabei que eu sou Deus; serei exaltado entre as nações.' Deus pede que seu povo pare e reconheça sua soberania.", reference:"Salmos 46:10", category:.salmos, propheticMeaning:"'Aquietai-vos' (refuah — larguem, deixem) é chamado à rendição à soberania de Deus. Na agitação do mundo, Cristo convida: 'Vinde a mim... e eu vos darei descanso' (Mt 11:28). O descanso vem ao reconhecer quem ele é."),
    QuizQuestion(id:159, question:"Qual é a promessa do Salmo 23:6?", options:["'Não temerei mal algum","'O Senhor é o meu pastor; nada me faltará'","'Ele me guia pelas veredas da justiça'","'Certamente que a bondade e a..."], correctIndex:3, explanation:"O Salmo 23 termina com: 'Certamente a bondade e a misericórdia me seguirão todos os dias da minha vida, e habitarei na casa do Senhor para sempre.'", reference:"Salmos 23:6", category:.salmos, propheticMeaning:"'Habitarei na casa do Senhor para sempre' é a esperança eterna do cristão — não apenas visitas a Deus, mas habitação permanente. Isso se cumpre em João 14:2-3: Jesus vai preparar lugar para que onde ele estiver, estejamos também."),
    QuizQuestion(id:160, question:"Qual salmo começa com 'Cantai ao Senhor um cântico novo'?", options:["Salmo 96","Salmo 100","Salmo 150","Salmo 33"], correctIndex:0, explanation:"O Salmo 96 começa: 'Cantai ao Senhor um cântico novo; cantai ao Senhor, toda a terra!' É um chamado à adoração universal.", reference:"Salmos 96:1", category:.salmos, propheticMeaning:"O 'cântico novo' é mencionado em Apocalipse 5:9 — o cântico que os remidos cantarão ao Cordeiro: 'Digno és de tomar o livro e de abrir os seus selos, porque foste morto e com o teu sangue compraste para Deus homens de toda tribo.'"),
    // ATOS E CARTAS (161-240)
    QuizQuestion(id:161, question:"Qual era o nome original do apóstolo Paulo antes de sua conversão?", options:["Barnabé","Saulo","Silas","Timóteo"], correctIndex:1, explanation:"Paulo era chamado de Saulo antes de sua conversão no caminho de Damasco. Era fariseu zeloso que perseguia cristãos.", reference:"Atos 9:1-4", category:.atos, propheticMeaning:"A conversão de Saulo — o maior perseguidor virando o maior missionário — é prova do poder transformador do evangelho. Cristo aparecendo a Saulo cumple Joel 2:28: o Espírito derramado sobre toda a carne."),
    QuizQuestion(id:162, question:"Quando o Espírito Santo desceu sobre os discípulos no Pentecostes?", options:["No primeiro dia da semana","No dia do Natal","50 dias após a Páscoa","No dia da Páscoa"], correctIndex:2, explanation:"O Espírito Santo desceu sobre os 120 discípulos no Pentecostes, 50 dias após a Páscoa, com línguas de fogo e vento impetuoso.", reference:"Atos 2:1-4", category:.atos, propheticMeaning:"O Pentecostes cumpre Joel 2:28-29: 'Derramarei do meu Espírito sobre toda a carne.' A festa das primícias (50 dias após a Páscoa) se torna o dia das primícias do Espírito — a Igreja nascendo como colheita inicial dos redimidos."),
    QuizQuestion(id:163, question:"Segundo Paulo em 1 Coríntios 13, qual é o maior dom?", options:["A fé","A esperança","A profecia","O amor"], correctIndex:3, explanation:"'Agora, pois, permanecem a fé, a esperança e o amor, estes três; mas o maior destes é o amor.' O amor é o fundamento e a culminação de todos os dons.", reference:"1 Coríntios 13:13", category:.atos, propheticMeaning:"O amor (agapê) que Paulo descreve em 1 Co 13 é o amor de Deus revelado em Cristo — suporta tudo, crê tudo, espera tudo, persevera em tudo. É o retrato do próprio Jesus, e é pela fé que esse amor é derramado em nós (Rm 5:5)."),
    QuizQuestion(id:164, question:"O que Paulo ensina em Filipenses 4:13?", options:["'Tudo posso naquele que me fortalece'","'Alegrai-vos sempre no Senhor'","'A paz de Deus guarda os corações'","'Pensai nas coisas verdadeiras'"], correctIndex:0, explanation:"'Tudo posso em Cristo que me fortalece.' Paulo escreveu isso da prisão, demonstrando que a força cristã não depende de circunstâncias.", reference:"Filipenses 4:13", category:.atos, propheticMeaning:"'Tudo posso em Cristo' não é otimismo humano — é capacitação sobrenatural pelo Espírito. A fraqueza humana se torna o palco onde o poder de Deus se manifesta plenamente (2 Co 12:9-10)."),
    QuizQuestion(id:165, question:"O que diz Romanos 8:28?", options:["'Se Deus é por nós, quem será contra nós?'","'Sabemos que todas as coisas cooperam","'Nada nos separará do amor de Deus'","'Não há condenação para os que estão em"], correctIndex:1, explanation:"'Sabemos que todas as coisas cooperam para o bem daqueles que amam a Deus, daqueles que são chamados segundo o seu propósito.'", reference:"Romanos 8:28", category:.atos, propheticMeaning:"'Todas as coisas' inclui sofrimento, perda e injustiça. A história de José é o protótipo: o que os irmãos fizeram para o mal, Deus usou para o bem (Gn 50:20). Cristo crucificado é a prova máxima: o maior mal se tornou o maior bem."),
    QuizQuestion(id:166, question:"Qual é o versículo inicial de João 1?", options:["'Deus é amor'","'Assim como o Pai me enviou","'No princípio era o Verbo'","'Em Cristo não há judeu nem grego'"], correctIndex:2, explanation:"'No princípio era o Verbo, e o Verbo estava com Deus, e o Verbo era Deus.' João 1:1 apresenta a eternidade e divindade de Jesus, o Logos.", reference:"João 1:1", category:.atos, propheticMeaning:"João 1:1 ecoa Gênesis 1:1 ('No princípio'). Cristo é o Criador e Sustentador de todas as coisas (Cl 1:16-17). A Palavra que criou o universo tornou-se carne para recriar a humanidade caída."),
    QuizQuestion(id:167, question:"O que Paulo ensina em Efésios 2:8-9?", options:["'Andai no Espírito e não cumprireis a...","'Todo o poder me foi dado no céu e na","'Apresentai os vossos corpos como...","'Porque pela graça sois salvos"], correctIndex:3, explanation:"'Porque pela graça sois salvos, mediante a fé, e isso não vem de vós; é dom de Deus. Não vem de obras, para que ninguém se glorie.'", reference:"Efésios 2:8-9", category:.atos, propheticMeaning:"A salvação pela graça mediante a fé é o coração do evangelho paulino — e de toda a Escritura. Abraão foi justificado pela fé (Gn 15:6; Rm 4:3); nós somos justificados pela fé em Cristo, o cumprimento de toda a promessa."),
    QuizQuestion(id:168, question:"O que aconteceu com Estêvão, o primeiro mártir cristão?", options:["Foi apedrejado até à morte","Foi preso e depois libertado","Foi crucificado como Jesus","Fugiu e pregou em outro país"], correctIndex:0, explanation:"Estêvão foi apedrejado pelo Sinédrio após um longo discurso bíblico. Em seus últimos momentos orou: 'Senhor Jesus, recebe o meu espírito... não os consideres culpados deste pecado.'", reference:"Atos 7:59-60", category:.atos, propheticMeaning:"Estêvão morrendo com as mesmas palavras de Jesus na cruz ('recebe meu espírito' e 'não os imputes este pecado') mostra que o martírio cristão é participação nos sofrimentos de Cristo (Fp 3:10). Sua morte plantou sementes: Saulo de Tarso estava lá."),
    QuizQuestion(id:169, question:"O que Paulo diz em Gálatas 2:20?", options:["'Porque para mim o viver é Cristo e o...","'Já estou crucificado com Cristo","'Tudo posso naquele que me fortalece'","'Nada nos separará do amor de Deus'"], correctIndex:1, explanation:"'Já estou crucificado com Cristo; e vivo, não mais eu, mas Cristo vive em mim; e esse viver que agora tenho na carne, vivo pela fé do Filho de Deus, que me amou e se entregou a si mesmo por mim.'", reference:"Gálatas 2:20", category:.atos, propheticMeaning:"'Cristo vive em mim' é a experiência da nova criação (2 Co 5:17). A co-crucificação com Cristo é o fundamento da vida cristã — morremos ao velho 'eu' e vivemos a nova vida de Cristo em nós pelo Espírito Santo."),
    QuizQuestion(id:170, question:"Qual é a famosa 'armadura de Deus' descrita por Paulo?", options:["Cinto, escudo e espada","Elmo, lança e broquél","Cinto da verdade","Anel de autoridade"], correctIndex:2, explanation:"Em Efésios 6:13-17, Paulo descreve cada peça da armadura espiritual do cristão para resistir ao diabo.", reference:"Efésios 6:13-17", category:.atos, propheticMeaning:"A armadura de Deus é o próprio Cristo — a verdade, a justiça, a paz, a fé, a salvação e a Palavra são atributos de Jesus que vestimos por fé (Rm 13:14: 'revesti-vos do Senhor Jesus Cristo'). Resistir ao diabo é permanecer em Cristo."),
    QuizQuestion(id:171, question:"O que Pedro pregou no dia de Pentecostes e quantos foram convertidos?", options:["Pregou sobre o amor de Deus e 1000 se","Pregou sobre o juízo e 500 se converteram","Pregou sobre a volta de Cristo e 5000","Pregou sobre a ressurreição de Cristo e..."], correctIndex:3, explanation:"Pedro pregou sobre a morte e ressurreição de Jesus cumprindo as profecias, e cerca de três mil pessoas se converteram e foram batizadas naquele dia.", reference:"Atos 2:41", category:.atos, propheticMeaning:"Os 3.000 convertidos em Pentecostes contrastam com os 3.000 mortos pela lei dourada (Êx 32:28). Onde a lei matou, o Espírito vivifica. A letra mata, mas o Espírito dá vida (2 Co 3:6) — o Pentecostes inaugurou a era da graça."),
    QuizQuestion(id:172, question:"Quem era Lidia, mencionada em Atos 16?", options:["Uma vendedeira de púrpura de","Esposa de Paulo","Uma profetissa de Filipos","Uma escrava liberta por Paulo"], correctIndex:0, explanation:"Lídia era uma comerciante de tecidos de púrpura de Tiatira. Ao ouvir Paulo pregar, o Senhor abriu seu coração, ela creu, foi batizada junto com sua família e hospedou os missionários.", reference:"Atos 16:14-15", category:.atos, propheticMeaning:"Lídia é o primeiro convertido europeu registrado — a porta de entrada do evangelho na Europa. Deus abre corações (não apenas mentes) para receber a fé: a iniciativa sempre é divina, a resposta humana é receptiva."),
    QuizQuestion(id:173, question:"Qual é o tema central do livro de Romanos?", options:["A vida da Igreja","A justificação pela fé e","A volta de Cristo","As obras do cristão"], correctIndex:1, explanation:"Romanos é a obra magna de Paulo sobre a justificação pela fé: o evangelho é poder de Deus para salvação, a justiça de Deus revelada de fé em fé (Rm 1:16-17).", reference:"Romanos 1:16-17", category:.atos, propheticMeaning:"Romanos cita Habacuque 2:4 ('o justo viverá pela fé') para mostrar que a fé sempre foi o meio de salvação — Abraão, Davi, o profeta e agora os crentes em Cristo todos participam da mesma justiça pela fé."),
    QuizQuestion(id:174, question:"O que Paulo ensina sobre a ressurreição em 1 Coríntios 15?", options:["Que a ressurreição é simbólica","Que somente os apóstolos ressuscitarão","Que Cristo ressuscitou corporalmente e...","Que a ressurreição acontece imediatamente"], correctIndex:2, explanation:"Paulo afirma que se Cristo não ressuscitou, nossa fé é vã. Mas Cristo ressuscitou como primícias dos que dormem, garantindo a ressurreição de todos os crentes.", reference:"1 Coríntios 15:20", category:.atos, propheticMeaning:"'Primícias' (aparche) é linguagem da festa das primícias — a primeira parcela que garante a colheita completa. Cristo ressuscitado é a garantia da nossa ressurreição. O que aconteceu a ele ACONTECERÁ a todos os que estão nele."),
    QuizQuestion(id:175, question:"Qual é a famosa passagem sobre o amor em 1 Coríntios 13?", options:["'O amor cobre multidão de pecados'","'Deus é amor'","'Nós amamos porque ele nos amou primeiro'","'O amor é paciente, é benigno"], correctIndex:3, explanation:"1 Coríntios 13:4-8 define o amor cristão com 15 características — um retrato do próprio caráter de Deus revelado em Cristo.", reference:"1 Coríntios 13:4", category:.atos, propheticMeaning:"Cada característica do amor em 1 Co 13 é perfeita em Cristo: ele foi paciente, benigno, não invejoso, não soberbo... sofreu tudo, creu tudo, esperou tudo. O hino do amor é a biografia de Jesus."),
    QuizQuestion(id:176, question:"O que Paulo diz em Romanos 10:9?", options:["'Se confessares com tua boca que Jesus é","'A fé vem pelo ouvir'","'Não há judeu nem grego'","'A remuneração do pecado é a morte'"], correctIndex:0, explanation:"'Se confessares com tua boca que Jesus é Senhor, e creres em teu coração que Deus o ressuscitou dos mortos, serás salvo.' A salvação é pela confissão da fé.", reference:"Romanos 10:9", category:.atos, propheticMeaning:"Confessar 'Jesus é Senhor' (Kyrios) é usar o título de Deus do AT (LXX usa Kyrios para YHWH). Paulo ensina que reconhecer a divindade e ressurreição de Cristo é o ato de fé salvífico que cumpre toda a promessa bíblica."),
    QuizQuestion(id:177, question:"Qual é a promessa de João 3:16?", options:["Que Deus nos dará saúde e prosperidade","Que todo o que crê em Jesus não perecerá","Que seremos livres de todo sofrimento","Que Deus nunca nos deixará"], correctIndex:1, explanation:"'Porque Deus amou o mundo de tal maneira que deu o seu Filho Unigênito, para que todo aquele que nele crê não pereça, mas tenha a vida eterna.'", reference:"João 3:16", category:.atos, propheticMeaning:"João 3:16 resume toda a narrativa bíblica: o amor eterno de Deus (desde antes da criação), manifestado no dom do Filho, recebido pela fé, resultando em vida eterna. É o coração do evangelho em uma frase."),
    QuizQuestion(id:178, question:"O que diz Hebreus 11:1?", options:["'Sem fé é impossível agradar a Deus'","'O justo viverá pela fé'","'A fé é a certeza das coisas que se","'Aproximemo-nos com confiança do trono da"], correctIndex:2, explanation:"'A fé é a certeza das coisas que se esperam e a prova das coisas que não se veem.' Hebreus 11 é o 'hall da fama' da fé bíblica.", reference:"Hebreus 11:1", category:.atos, propheticMeaning:"Hebreus 11 mostra que todos os heróis da fé agiam baseados em promessas não vistas ainda. Todos 'morreram na fé, sem ter recebido as promessas' (v.13), pois aguardavam Cristo — a substância de toda esperança."),
    QuizQuestion(id:179, question:"O que Paulo diz em Filipenses 4:6-7?", options:["'Tudo posso naquele que me fortalece'","'Alegrai-vos sempre no Senhor'","'Pensai nas coisas verdadeiras, honestas","'Nada ansieis"], correctIndex:3, explanation:"'Nada ansieis, mas em tudo pela oração e súplica com ações de graças fazei os vossos pedidos conhecidos a Deus, e a paz de Deus que excede todo entendimento guardará os vossos corações.'", reference:"Filipenses 4:6-7", category:.atos, propheticMeaning:"A paz que 'excede todo entendimento' é sobrenatural — não ausência de problemas, mas presença de Cristo. Jesus disse: 'Deixo-vos a paz, a minha paz vos dou' (Jo 14:27). Oração transforma ansiedade em paz sobrenatural."),
    QuizQuestion(id:180, question:"Quantas cartas Paulo escreveu no Novo Testamento?", options:["13","7","10","15"], correctIndex:0, explanation:"Paulo escreveu 13 cartas no NT: Romanos, 1 e 2 Coríntios, Gálatas, Efésios, Filipenses, Colossenses, 1 e 2 Tessalonicenses, 1 e 2 Timóteo, Tito e Filemom.", reference:"Novo Testamento", category:.atos, propheticMeaning:"As 13 cartas de Paulo cobrem toda a teologia do evangelho: justificação (Rm, Gl), vida na Igreja (1-2 Co), escatologia (1-2 Ts), e maturidade cristã (Ef, Fp, Cl). Cristo é o tema central de todas."),
]
